CREATE VIEW `ads_ad_unlock_chapter_detail_view` (`product_id` COMMENT "产品id", `id` COMMENT "自增id", `pid` COMMENT "用户id", `book_id` COMMENT "书籍id", `chapter_id` COMMENT "章节id", `unlock_time` COMMENT "解锁时间", `unlock_count` COMMENT "解锁次数", `device_id` COMMENT "设备id", `lock_type` COMMENT "解锁类型")
COMMENT "广告解锁章节明细视图" AS SELECT `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`product_id`, `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`Id`, `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`Pid`, `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`BookId` AS `book_id`, `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`ChapterId` AS `chapter_id`, `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`UnlockTime` AS `unlock_time`, `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`UnlockCount` AS `unlock_count`, `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`DeviceId` AS `device_id`, `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`.`LockType` AS `lock_type`
FROM `ods`.`ods_tidb_readernovel_tidb_xx_adunlockchapter`;